import os
import datetime
import functools
import re

from flask import Flask, request, jsonify, g
import jwt
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Configuration
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY', os.urandom(32).hex())
app.config['JWT_ALGORITHM'] = 'HS256'
app.config['JWT_EXPIRATION_HOURS'] = 1
app.config['JWT_ISSUER'] = 'flask-jwt-auth'

# In-memory user store (replace with a database in production)
users_db = {}


class AuthError(Exception):
    """Custom authentication error."""
    def __init__(self, message, status_code=401):
        super().__init__(message)
        self.message = message
        self.status_code = status_code


@app.errorhandler(AuthError)
def handle_auth_error(error):
    return jsonify({'error': error.message}), error.status_code


def validate_password_strength(password):
    """Enforce minimum password requirements."""
    if len(password) < 8:
        return False, "Password must be at least 8 characters long."
    if not re.search(r'[A-Z]', password):
        return False, "Password must contain at least one uppercase letter."
    if not re.search(r'[a-z]', password):
        return False, "Password must contain at least one lowercase letter."
    if not re.search(r'[0-9]', password):
        return False, "Password must contain at least one digit."
    return True, "Password is valid."


def generate_token(user_id, username):
    """Generate a secure JWT token with proper claims."""
    now = datetime.datetime.now(datetime.timezone.utc)
    payload = {
        'sub': user_id,
        'username': username,
        'iat': now,
        'exp': now + datetime.timedelta(hours=app.config['JWT_EXPIRATION_HOURS']),
        'nbf': now,
        'iss': app.config['JWT_ISSUER'],
        'jti': os.urandom(16).hex(),  # Unique token ID to prevent replay
    }
    token = jwt.encode(
        payload,
        app.config['SECRET_KEY'],
        algorithm=app.config['JWT_ALGORITHM']
    )
    return token


def decode_token(token):
    """Decode and validate a JWT token securely."""
    try:
        payload = jwt.decode(
            token,
            app.config['SECRET_KEY'],
            algorithms=[app.config['JWT_ALGORITHM']],  # Explicitly whitelist algorithm
            options={
                'require': ['sub', 'username', 'iat', 'exp', 'nbf', 'iss', 'jti'],
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
                'verify_iss': True,
            },
            issuer=app.config['JWT_ISSUER'],
        )
        return payload
    except jwt.ExpiredSignatureError:
        raise AuthError('Token has expired. Please log in again.')
    except jwt.InvalidIssuerError:
        raise AuthError('Invalid token issuer.')
    except jwt.ImmatureSignatureError:
        raise AuthError('Token is not yet valid.')
    except jwt.InvalidTokenError as e:
        raise AuthError(f'Invalid token: {str(e)}')


def token_required(f):
    """Decorator to protect routes with JWT authentication."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Extract token from Authorization header
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header[7:].strip()

        if not token:
            raise AuthError('Authentication token is missing. Provide a Bearer token in the Authorization header.')

        # Basic token format validation before decoding
        if len(token) > 2048:
            raise AuthError('Token is too long.')

        payload = decode_token(token)

        # Verify user still exists
        user_id = payload.get('sub')
        if user_id not in users_db:
            raise AuthError('User no longer exists.', 401)

        # Store user info in Flask's g object for the request context
        g.current_user = {
            'user_id': user_id,
            'username': payload.get('username'),
        }

        return f(*args, **kwargs)

    return decorated


def admin_required(f):
    """Decorator for admin-only routes (extends token_required)."""
    @functools.wraps(f)
    @token_required
    def decorated(*args, **kwargs):
        user = users_db.get(g.current_user['user_id'], {})
        if not user.get('is_admin', False):
            raise AuthError('Admin privileges required.', 403)
        return f(*args, **kwargs)
    return decorated


@app.route('/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON.'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required.'}), 400

    # Validate username
    if len(username) < 3 or len(username) > 50:
        return jsonify({'error': 'Username must be between 3 and 50 characters.'}), 400

    if not re.match(r'^[a-zA-Z0-9_]+$', username):
        return jsonify({'error': 'Username can only contain letters, numbers, and underscores.'}), 400

    # Check if username already exists
    for uid, user in users_db.items():
        if user['username'].lower() == username.lower():
            return jsonify({'error': 'Username already exists.'}), 409

    # Validate password strength
    is_valid, message = validate_password_strength(password)
    if not is_valid:
        return jsonify({'error': message}), 400

    # Create user
    user_id = os.urandom(16).hex()
    users_db[user_id] = {
        'user_id': user_id,
        'username': username,
        'password_hash': generate_password_hash(password),
        'is_admin': False,
        'created_at': datetime.datetime.now(datetime.timezone.utc).isoformat(),
    }

    return jsonify({
        'message': 'User registered successfully.',
        'user_id': user_id,
        'username': username,
    }), 201


@app.route('/auth/login', methods=['POST'])
def login():
    """Authenticate user and return JWT token."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON.'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required.'}), 400

    # Find user by username (constant-time-ish lookup to avoid timing attacks)
    found_user = None
    for uid, user in users_db.items():
        if user['username'].lower() == username.lower():
            found_user = user
            break

    # Use generic error message to prevent user enumeration
    if not found_user or not check_password_hash(found_user['password_hash'], password):
        return jsonify({'error': 'Invalid username or password.'}), 401

    # Generate token
    token = generate_token(found_user['user_id'], found_user['username'])

    return jsonify({
        'message': 'Login successful.',
        'token': token,
        'token_type': 'Bearer',
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600,
    }), 200


@app.route('/auth/refresh', methods=['POST'])
@token_required
def refresh_token():
    """Refresh an existing valid token."""
    new_token = generate_token(
        g.current_user['user_id'],
        g.current_user['username']
    )

    return jsonify({
        'message': 'Token refreshed successfully.',
        'token': new_token,
        'token_type': 'Bearer',
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600,
    }), 200


@app.route('/auth/me', methods=['GET'])
@token_required
def get_current_user():
    """Get current authenticated user's profile."""
    user = users_db.get(g.current_user['user_id'])
    return jsonify({
        'user_id': user['user_id'],
        'username': user['username'],
        'is_admin': user.get('is_admin', False),
        'created_at': user.get('created_at'),
    }), 200


@app.route('/auth/change-password', methods=['POST'])
@token_required
def change_password():
    """Change the current user's password."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body must be JSON.'}), 400

    current_password = data.get('current_password', '')
    new_password = data.get('new_password', '')

    if not current_password or not new_password:
        return jsonify({'error': 'Current password and new password are required.'}), 400

    user = users_db.get(g.current_user['user_id'])

    if not check_password_hash(user['password_hash'], current_password):
        return jsonify({'error': 'Current password is incorrect.'}), 401

    is_valid, message = validate_password_strength(new_password)
    if not is_valid:
        return jsonify({'error': message}), 400

    user['password_hash'] = generate_password_hash(new_password)

    return jsonify({'message': 'Password changed successfully.'}), 200


# Example protected routes

@app.route('/api/public', methods=['GET'])
def public_route():
    """A public endpoint that doesn't require authentication."""
    return jsonify({'message': 'This is a public endpoint. No authentication required.'}), 200


@app.route('/api/protected', methods=['GET'])
@token_required
def protected_route():
    """A protected endpoint that requires a valid JWT token."""
    return jsonify({
        'message': 'You have access to this protected resource.',
        'user': g.current_user,
    }), 200


@app.route('/api/admin', methods=['GET'])
@admin_required
def admin_route():
    """An admin-only endpoint."""
    return jsonify({
        'message': 'Welcome, admin!',
        'user': g.current_user,
        'total_users': len(users_db),
    }), 200


@app.route('/api/users', methods=['GET'])
@admin_required
def list_users():
    """List all users (admin only)."""
    user_list = [
        {
            'user_id': u['user_id'],
            'username': u['username'],
            'is_admin': u.get('is_admin', False),
            'created_at': u.get('created_at'),
        }
        for u in users_db.values()
    ]
    return jsonify({'users': user_list, 'total': len(user_list)}), 200


# Security headers middleware
@app.after_request
def add_security_headers(response):
    """Add security headers to all responses."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    return response


